def lcs_length(a,b):
    # dynamic programming O(n*m)
    n,m=len(a),len(b)
    dp=[0]*(m+1)
    for i in range(1,n+1):
        prev=0
        for j in range(1,m+1):
            temp=dp[j]
            if a[i-1]==b[j-1]:
                dp[j]=prev+1
            else:
                dp[j]=max(dp[j], dp[j-1])
            prev=temp
    return dp[m]

def lcs_ratio(a,b):
    a_norm=a
    b_norm=b
    l=lcs_length(a_norm, b_norm)
    return l/len(a_norm), l/len(b_norm), l, len(a_norm), len(b_norm)

